package com.tourya.api.constans.enums;import jakarta.persistence.AttributeConverter;import jakarta.persistence.Converter;@Converterpublic class ProviderDocumentTypeEnumConverter implements AttributeConverter<ProviderDocumentTypeEnum, String>    {        public String convertToDatabaseColumn(ProviderDocumentTypeEnum value) {        if ( value == null ) {            return null;        }        return value.getValue();    }        public ProviderDocumentTypeEnum convertToEntityAttribute(String value) {        if ( value == null ) {            return null;        }        return ProviderDocumentTypeEnum.of(value);    }}